var pbr_helper = '#include <normal_get>\n#include <brdf>\n#include <btdf>\n\n// direct + indirect\n#include <direct_irradiance_frag_define>\n#include <ibl_frag_define>\n\nuniform sampler2D camera_AOTexture;\n\nfloat evaluateAmbientOcclusion(vec2 uv)\n{\n    #ifdef MATERIAL_IS_TRANSPARENT\n        return 1.0;\n    #else\n        return texture2D(camera_AOTexture, uv).r;\n    #endif\n}\n\n\nfloat computeSpecularOcclusion(float ambientOcclusion, float roughness, float dotNV ) {\n    return saturate( pow( dotNV + ambientOcclusion, exp2( - 16.0 * roughness - 1.0 ) ) - 1.0 + ambientOcclusion );\n}\n\nfloat getAARoughnessFactor(vec3 normal) {\n    // Kaplanyan 2016, "Stable specular highlights"\n    // Tokuyoshi 2017, "Error Reduction and Simplification for Shading Anti-Aliasing"\n    // Tokuyoshi and Kaplanyan 2019, "Improved Geometric Specular Antialiasing"\n    #ifdef HAS_DERIVATIVES\n        vec3 dxy = max( abs(dFdx(normal)), abs(dFdy(normal)) );\n        return max( max(dxy.x, dxy.y), dxy.z );\n    #else\n        return 0.0;\n    #endif\n}\n\n#ifdef MATERIAL_ENABLE_ANISOTROPY\n    // Aniso Bent Normals\n    // Mc Alley https://www.gdcvault.com/play/1022235/Rendering-the-World-of-Far \n    vec3 getAnisotropicBentNormal(Geometry geometry, vec3 n, float roughness) {\n        vec3  anisotropyDirection = geometry.anisotropy >= 0.0 ? geometry.anisotropicB : geometry.anisotropicT;\n        vec3  anisotropicTangent  = cross(anisotropyDirection, geometry.viewDir);\n        vec3  anisotropicNormal   = cross(anisotropicTangent, anisotropyDirection);\n        // reduce stretching for (roughness < 0.2), refer to https://advances.realtimerendering.com/s2018/Siggraph%202018%20HDRP%20talk_with%20notes.pdf 80\n        vec3  bentNormal          = normalize( mix(n, anisotropicNormal, abs(geometry.anisotropy) * saturate( 5.0 * roughness)) );\n\n        return bentNormal;\n    }\n#endif\n\nvoid initGeometry(out Geometry geometry, bool isFrontFacing){\n    geometry.position = v_pos;\n    #ifdef CAMERA_ORTHOGRAPHIC\n        geometry.viewDir =  -camera_Forward;\n    #else\n        geometry.viewDir =  normalize(camera_Position - v_pos);\n    #endif\n    #if defined(MATERIAL_HAS_NORMALTEXTURE) || defined(MATERIAL_HAS_CLEAR_COAT_NORMAL_TEXTURE) || defined(MATERIAL_ENABLE_ANISOTROPY)\n        mat3 tbn = getTBN(isFrontFacing);\n    #endif\n\n    #ifdef MATERIAL_HAS_NORMALTEXTURE\n        geometry.normal = getNormalByNormalTexture(tbn, material_NormalTexture, material_NormalIntensity, v_uv, isFrontFacing);\n    #else\n        geometry.normal = getNormal(isFrontFacing);\n    #endif\n\n    geometry.dotNV = saturate( dot(geometry.normal, geometry.viewDir) );\n\n\n    #ifdef MATERIAL_ENABLE_CLEAR_COAT\n        #ifdef MATERIAL_HAS_CLEAR_COAT_NORMAL_TEXTURE\n            geometry.clearCoatNormal = getNormalByNormalTexture(tbn, material_ClearCoatNormalTexture, material_NormalIntensity, v_uv, isFrontFacing);\n        #else\n            geometry.clearCoatNormal = getNormal(isFrontFacing);\n        #endif\n        geometry.clearCoatDotNV = saturate( dot(geometry.clearCoatNormal, geometry.viewDir) );\n    #endif\n\n    #ifdef MATERIAL_ENABLE_ANISOTROPY\n        float anisotropy = material_AnisotropyInfo.z;\n        vec3 anisotropicDirection = vec3(material_AnisotropyInfo.xy, 0.0);\n        #ifdef MATERIAL_HAS_ANISOTROPY_TEXTURE\n            vec3 anisotropyTextureInfo = texture2D( material_AnisotropyTexture, v_uv ).rgb;\n            anisotropy *= anisotropyTextureInfo.b;\n            anisotropicDirection.xy *= anisotropyTextureInfo.rg * 2.0 - 1.0;\n        #endif\n\n        geometry.anisotropy = anisotropy;\n        geometry.anisotropicT = normalize(tbn * anisotropicDirection);\n        geometry.anisotropicB = normalize(cross(geometry.normal, geometry.anisotropicT));\n    #endif\n}\n\nvoid initMaterial(out Material material, inout Geometry geometry){\n        vec4 baseColor = material_BaseColor;\n        float metal = material_Metal;\n        float roughness = material_Roughness;\n        float alphaCutoff = material_AlphaCutoff;\n        material.IOR = material_IOR;\n\n        #ifdef MATERIAL_HAS_BASETEXTURE\n            baseColor *= texture2DSRGB(material_BaseTexture, v_uv);\n        #endif\n\n        #ifdef RENDERER_ENABLE_VERTEXCOLOR\n            baseColor *= v_color;\n        #endif\n\n\n        #ifdef MATERIAL_IS_ALPHA_CUTOFF\n            if( baseColor.a < alphaCutoff ) {\n                discard;\n            }\n        #endif\n\n        #ifdef MATERIAL_HAS_ROUGHNESS_METALLIC_TEXTURE\n            vec4 metalRoughMapColor = texture2D( material_RoughnessMetallicTexture, v_uv );\n            roughness *= metalRoughMapColor.g;\n            metal *= metalRoughMapColor.b;\n        #endif\n\n        // Specular\n        material.specularIntensity = material_SpecularIntensity;\n        material.specularColor = material_SpecularColor;\n        #ifdef MATERIAL_HAS_SPECULAR_TEXTURE\n            material.specularIntensity *= texture2D( material_SpecularIntensityTexture, v_uv ).a;\n        #endif\n\n        #ifdef MATERIAL_ENABLE_CLEAR_COAT\n            material.clearCoat = material_ClearCoat;\n            material.clearCoatRoughness = material_ClearCoatRoughness;\n            #ifdef MATERIAL_HAS_CLEAR_COAT_TEXTURE\n                material.clearCoat *= texture2D( material_ClearCoatTexture, v_uv ).r;\n            #endif\n            #ifdef MATERIAL_HAS_CLEAR_COAT_ROUGHNESS_TEXTURE\n                material.clearCoatRoughness *= texture2D( material_ClearCoatRoughnessTexture, v_uv ).g;\n            #endif\n            material.clearCoat = saturate( material.clearCoat );\n            material.clearCoatRoughness = max(MIN_PERCEPTUAL_ROUGHNESS, min(material.clearCoatRoughness + getAARoughnessFactor(geometry.clearCoatNormal), 1.0));\n        #endif\n\n        #ifdef MATERIAL_IS_TRANSPARENT\n            material.opacity = baseColor.a;\n        #else\n            material.opacity = 1.0;\n        #endif\n\n        material.roughness = max(MIN_PERCEPTUAL_ROUGHNESS, min(roughness + getAARoughnessFactor(geometry.normal), 1.0));\n\n        #ifdef MATERIAL_ENABLE_ANISOTROPY\n            geometry.anisotropicN = getAnisotropicBentNormal(geometry, geometry.normal, material.roughness);\n        #endif\n\n        vec3 dielectricBaseF0 = vec3(pow2( (material.IOR - 1.0) / (material.IOR  + 1.0) ));\n        vec3 dielectricF0 = min(dielectricBaseF0 * material.specularColor , vec3(1.0)) * material.specularIntensity;\n        float dielectricF90 = material.specularIntensity;  \n\n        material.specularF0 = mix(dielectricF0, baseColor.rgb, metal);\n        material.specularF90 = mix(dielectricF90, 1.0, metal);\n\n        // Simplify: albedoColor * mix((1.0 - max(max(dielectricF0.r,dielectricF0.g),dielectricF0.b)), 0.0, metallic);\n        material.diffuseColor = baseColor.rgb * (1.0 - metal) * (1.0 - max(max(dielectricF0.r,dielectricF0.g),dielectricF0.b));\n        material.envSpecularDFG = envBRDFApprox(material.specularF0, material.specularF90, material.roughness, geometry.dotNV );\n\n        // AO\n        float diffuseAO = 1.0;\n        float specularAO = 1.0;\n\n        #ifdef MATERIAL_HAS_OCCLUSION_TEXTURE\n            vec2 aoUV = v_uv;\n            #ifdef RENDERER_HAS_UV1\n                if(material_OcclusionTextureCoord == 1.0){\n                    aoUV = v_uv1;\n                }\n            #endif\n            diffuseAO = ((texture2D(material_OcclusionTexture, aoUV)).r - 1.0) * material_OcclusionIntensity + 1.0;\n        #endif\n\n         #ifdef SCENE_ENABLE_AMBIENT_OCCLUSION\n            float ambientAO = evaluateAmbientOcclusion((v_PositionCS.xy / v_PositionCS.w) * 0.5 + 0.5);\n            diffuseAO = min(diffuseAO, ambientAO);\n        #endif\n\n        #if (defined(MATERIAL_HAS_OCCLUSION_TEXTURE) || defined(SCENE_ENABLE_AMBIENT_OCCLUSION))&& defined(SCENE_USE_SPECULAR_ENV) \n            specularAO = saturate( pow( geometry.dotNV + diffuseAO, exp2( - 16.0 * material.roughness - 1.0 ) ) - 1.0 + diffuseAO );\n        #endif\n\n        material.diffuseAO = diffuseAO;\n        material.specularAO = specularAO;\n\n        // Sheen\n        #ifdef MATERIAL_ENABLE_SHEEN\n            vec3 sheenColor = material_SheenColor;\n            #ifdef MATERIAL_HAS_SHEEN_TEXTURE\n                sheenColor *= texture2DSRGB(material_SheenTexture, v_uv).rgb;\n            #endif\n            material.sheenColor = sheenColor;\n\n            material.sheenRoughness = material_SheenRoughness;\n            #ifdef MATERIAL_HAS_SHEEN_ROUGHNESS_TEXTURE\n                material.sheenRoughness *= texture2D(material_SheenRoughnessTexture, v_uv).a;\n            #endif\n\n            material.sheenRoughness = max(MIN_PERCEPTUAL_ROUGHNESS, min(material.sheenRoughness + getAARoughnessFactor(geometry.normal), 1.0));\n            material.approxIBLSheenDG = prefilteredSheenDFG(geometry.dotNV, material.sheenRoughness);\n            material.sheenScaling = 1.0 - material.approxIBLSheenDG * max(max(material.sheenColor.r, material.sheenColor.g), material.sheenColor.b);\n        #endif\n\n        // Iridescence\n        #ifdef MATERIAL_ENABLE_IRIDESCENCE\n            material.iridescenceFactor = material_IridescenceInfo.x;\n            material.iridescenceIOR = material_IridescenceInfo.y;\n\n            #ifdef MATERIAL_HAS_IRIDESCENCE_THICKNESS_TEXTURE\n               float iridescenceThicknessWeight = texture2D( material_IridescenceThicknessTexture, v_uv).g;\n               material.iridescenceThickness = mix(material_IridescenceInfo.z, material_IridescenceInfo.w, iridescenceThicknessWeight);\n            #else\n               material.iridescenceThickness = material_IridescenceInfo.w;\n            #endif\n\n            #ifdef MATERIAL_HAS_IRIDESCENCE_TEXTURE\n               material.iridescenceFactor *= texture2D( material_IridescenceTexture, v_uv).r;\n            #endif\n             \n            #ifdef MATERIAL_ENABLE_IRIDESCENCE\n                float topIOR = 1.0;\n                material.iridescenceSpecularColor = evalIridescenceSpecular(topIOR, geometry.dotNV, material.iridescenceIOR, material.specularF0, material.specularF90, material.iridescenceThickness);   \n            #endif\n        #endif\n\n        // Transmission\n        #ifdef MATERIAL_ENABLE_TRANSMISSION \n            material.transmission = material_Transmission;\n            #ifdef MATERIAL_HAS_TRANSMISSION_TEXTURE\n                material.transmission *= texture2D(material_TransmissionTexture, v_uv).r;\n            #endif\n\n            #ifdef MATERIAL_HAS_THICKNESS\n                material.absorptionCoefficient = -log(material_AttenuationColor + HALF_EPS) / max(HALF_EPS, material_AttenuationDistance);\n                material.thickness = max(material_Thickness, 0.0001);\n                #ifdef MATERIAL_HAS_THICKNESS_TEXTURE\n                    material.thickness *= texture2D( material_ThicknessTexture, v_uv).g;\n                #endif\n            #endif    \n        #endif\n}\n\n\n\n';
var brdf = `
#ifdef MATERIAL_ENABLE_SHEEN
    uniform sampler2D scene_PrefilteredDFG;
#endif

float F_Schlick(float f0, float f90, float dotLH) {
	return f0 + (f90 - f0) * (pow(1.0 - dotLH, 5.0));
}

vec3 F_Schlick(vec3 f0, float f90, float dotLH ) {

	// Original approximation by Christophe Schlick '94
	// float fresnel = pow( 1.0 - dotLH, 5.0 );

	// Optimized variant (presented by Epic at SIGGRAPH '13)
	// https://cdn2.unrealengine.com/Resources/files/2013SiggraphPresentationsNotes-26915738.pdf
	float fresnel = exp2( ( -5.55473 * dotLH - 6.98316 ) * dotLH );

	return (f90 - f0 ) * fresnel + f0;

}

// Moving Frostbite to Physically Based Rendering 3.0 - page 12, listing 2
// https://seblagarde.files.wordpress.com/2015/07/course_notes_moving_frostbite_to_pbr_v32.pdf
float G_GGX_SmithCorrelated(float alpha, float dotNL, float dotNV ) {

	float a2 = pow2( alpha );

	// dotNL and dotNV are explicitly swapped. This is not a mistake.
	float gv = dotNL * sqrt( a2 + ( 1.0 - a2 ) * pow2( dotNV ) );
	float gl = dotNV * sqrt( a2 + ( 1.0 - a2 ) * pow2( dotNL ) );

	return 0.5 / max( gv + gl, EPSILON );

}

#ifdef MATERIAL_ENABLE_ANISOTROPY
    // Heitz 2014, "Understanding the Masking-Shadowing Function in Microfacet-Based BRDFs"
    // Heitz http://jcgt.org/published/0003/02/03/paper.pdf
    float G_GGX_SmithCorrelated_Anisotropic(float at, float ab, float ToV, float BoV, float ToL, float BoL, float NoV, float NoL) {
        float lambdaV = NoL * length(vec3(at * ToV, ab * BoV, NoV));
        float lambdaL = NoV * length(vec3(at * ToL, ab * BoL, NoL));
        return 0.5 / max(lambdaV + lambdaL, EPSILON);
    }
#endif

// Microfacet Models for Refraction through Rough Surfaces - equation (33)
// http://graphicrants.blogspot.com/2013/08/specular-brdf-reference.html
// alpha is "roughness squared" in Disney\u2019s reparameterization
float D_GGX(float alpha, float dotNH ) {

	float a2 = pow2( alpha );

	float denom = pow2( dotNH ) * ( a2 - 1.0 ) + 1.0; // avoid alpha = 0 with dotNH = 1

	return RECIPROCAL_PI * a2 / pow2( denom );

}

#ifdef MATERIAL_ENABLE_SHEEN
    // http://www.aconty.com/pdf/s2017_pbs_imageworks_sheen.pdf
    float D_Charlie(float roughness, float dotNH) {
        float invAlpha  = 1.0 / roughness;
        float cos2h = dotNH * dotNH;
        float sin2h = max(1.0 - cos2h, 0.0078125); // 2^(-14/2), so sin2h^2 > 0 in fp16
        return (2.0 + invAlpha) * pow(sin2h, invAlpha * 0.5) / (2.0 * PI);
    }

    // Neubelt and Pettineo 2013, "Crafting a Next-gen Material Pipeline for The Order: 1886".
    float V_Neubelt(float NoV, float NoL) {
        return saturate(1.0 / (4.0 * (NoL + NoV - NoL * NoV)));
    }

    vec3 sheenBRDF(vec3 incidentDirection, Geometry geometry, vec3 sheenColor, float sheenRoughness) {
        vec3 halfDir = normalize(incidentDirection + geometry.viewDir);
        float dotNL = saturate(dot(geometry.normal, incidentDirection));
        float dotNH = saturate(dot(geometry.normal, halfDir));
        float D = D_Charlie(sheenRoughness, dotNH);
        float V = V_Neubelt(geometry.dotNV, dotNL);
        vec3 F = sheenColor;
        return  D * V * F;
    }

    float prefilteredSheenDFG(float dotNV, float sheenRoughness) {
        #ifdef HAS_TEX_LOD
            return texture2DLodEXT(scene_PrefilteredDFG, vec2(dotNV, sheenRoughness), 0.0).b;
        #else
            return texture2D(scene_PrefilteredDFG, vec2(dotNV, sheenRoughness),0.0).b;
        #endif  
    }
#endif

#ifdef MATERIAL_ENABLE_ANISOTROPY
    // GGX Distribution Anisotropic
    // https://blog.selfshadow.com/publications/s2012-shading-course/burley/s2012_pbs_disney_brdf_notes_v3.pdf Addenda
    float D_GGX_Anisotropic(float at, float ab, float ToH, float BoH, float NoH) {
        float a2 = at * ab;
        vec3 d = vec3(ab * ToH, at * BoH, a2 * NoH);
        float d2 = dot(d, d);
        float b2 = a2 / d2;
        return a2 * b2 * b2 * RECIPROCAL_PI;
    }
#endif

float DG_GGX(float alpha, float dotNV, float dotNL, float dotNH) {
	float D = D_GGX( alpha, dotNH );
	float G = G_GGX_SmithCorrelated( alpha, dotNL, dotNV );
    return G * D;
}

#ifdef MATERIAL_ENABLE_ANISOTROPY
    float DG_GGX_anisotropic(vec3 h, vec3 l, Geometry geometry, float alpha, float dotNV, float dotNL, float dotNH) {
        vec3 t = geometry.anisotropicT;
        vec3 b = geometry.anisotropicB;
        vec3 v = geometry.viewDir;

        float dotTV = dot(t, v);
        float dotBV = dot(b, v);
        float dotTL = dot(t, l);
        float dotBL = dot(b, l);
        float dotTH = dot(t, h);
        float dotBH = dot(b, h);

        // Aniso parameter remapping
        // https://blog.selfshadow.com/publications/s2017-shading-course/imageworks/s2017_pbs_imageworks_slides_v2.pdf page 24
        float at = max(alpha * (1.0 + geometry.anisotropy), MIN_ROUGHNESS);
        float ab = max(alpha * (1.0 - geometry.anisotropy), MIN_ROUGHNESS);

        // specular anisotropic BRDF
        float D = D_GGX_Anisotropic(at, ab, dotTH, dotBH, dotNH);
        float G = G_GGX_SmithCorrelated_Anisotropic(at, ab, dotTV, dotBV, dotTL, dotBL, dotNV, dotNL);

        return G * D;
    }
#endif

#ifdef MATERIAL_ENABLE_IRIDESCENCE
    vec3 iorToFresnel0(vec3 transmittedIOR, float incidentIOR) {
        return pow((transmittedIOR - incidentIOR) / (transmittedIOR + incidentIOR),vec3(2.0));
    } 

    float iorToFresnel0(float transmittedIOR, float incidentIOR) {
        return pow((transmittedIOR - incidentIOR) / (transmittedIOR + incidentIOR),2.0);
    } 

    // Assume air interface for top
    // Note: We don't handle the case fresnel0 == 1
    vec3 fresnelToIOR(vec3 f0){
        vec3 sqrtF0 = sqrt(f0);
        return (vec3(1.0) + sqrtF0) / (vec3(1.0) - sqrtF0);
    }

    // Fresnel equations for dielectric/dielectric interfaces.
    // Ref: https://belcour.github.io/blog/research/publication/2017/05/01/brdf-thin-film.html
    // Evaluation XYZ sensitivity curves in Fourier space
    vec3 evalSensitivity(float opd, vec3 shift){
        // Use Gaussian fits, given by 3 parameters: val, pos and var
        float phase = 2.0 * PI * opd * 1.0e-9;
        const vec3 val = vec3(5.4856e-13, 4.4201e-13, 5.2481e-13);
        const vec3 pos = vec3(1.6810e+06, 1.7953e+06, 2.2084e+06);
        const vec3 var = vec3(4.3278e+09, 9.3046e+09, 6.6121e+09);
        vec3 xyz = val * sqrt(2.0 * PI * var) * cos(pos * phase + shift) * exp(-var * pow2(phase));
        xyz.x += 9.7470e-14 * sqrt(2.0 * PI * 4.5282e+09) * cos(2.2399e+06 * phase + shift[0]) * exp(-4.5282e+09 * pow2(phase));
        xyz /= 1.0685e-7;
        // XYZ to RGB color space
        const mat3 XYZ_TO_RGB = mat3( 3.2404542, -0.9692660,  0.0556434,
                                     -1.5371385,  1.8760108, -0.2040259,
                                     -0.4985314,  0.0415560,  1.0572252);
        vec3 rgb = XYZ_TO_RGB * xyz;
        return rgb;
    }

    vec3 evalIridescenceSpecular(float outsideIOR, float dotNV, float thinIOR, vec3 baseF0, float baseF90, float iridescenceThickness){ 
        vec3 iridescence = vec3(1.0);
        // Force iridescenceIOR -> outsideIOR when thinFilmThickness -> 0.0
        float iridescenceIOR = mix( outsideIOR, thinIOR, smoothstep( 0.0, 0.03, iridescenceThickness ) );
        // Evaluate the cosTheta on the base layer (Snell law)
        float sinTheta2Sq = pow( outsideIOR / iridescenceIOR, 2.0) * (1.0 - pow( dotNV, 2.0));
        float cosTheta2Sq = 1.0 - sinTheta2Sq;
        // Handle total internal reflection
        if (cosTheta2Sq < 0.0) {
           return iridescence;
        }
        float cosTheta2 = sqrt(cosTheta2Sq);
            
        // First interface
        float f0 = iorToFresnel0(iridescenceIOR, outsideIOR);
        float reflectance = F_Schlick(f0, baseF90, dotNV);
        float t121 = 1.0 - reflectance;
        float phi12 = 0.0;
        // iridescenceIOR has limited greater than 1.0
        // if (iridescenceIOR < outsideIOR) {phi12 = PI;} 
        float phi21 = PI - phi12;
        
        // Second interface
        vec3 baseIOR = fresnelToIOR(clamp(baseF0, 0.0, 0.9999)); // guard against 1.0
        vec3 r1  = iorToFresnel0(baseIOR, iridescenceIOR);
        vec3 r23 = F_Schlick(r1, baseF90, cosTheta2);
        vec3 phi23 =vec3(0.0);
        if (baseIOR[0] < iridescenceIOR) {phi23[0] = PI;}
        if (baseIOR[1] < iridescenceIOR) {phi23[1] = PI;}
        if (baseIOR[2] < iridescenceIOR) {phi23[2] = PI;}
        
        // Phase shift
        float opd = 2.0 * iridescenceIOR  * iridescenceThickness * cosTheta2;
        vec3 phi = vec3(phi21) + phi23;
        
        // Compound terms
        vec3 r123 = clamp(reflectance * r23, 1e-5, 0.9999);
        vec3 sr123 = sqrt(r123);
        vec3 rs = pow2(t121) * r23 / (vec3(1.0) - r123);
        // Reflectance term for m = 0 (DC term amplitude)
        vec3 c0 = reflectance + rs;
        iridescence = c0;
        // Reflectance term for m > 0 (pairs of diracs)
        vec3 cm = rs - t121;
        for (int m = 1; m <= 2; ++m) {
             cm *= sr123;
             vec3 sm = 2.0 * evalSensitivity(float(m) * opd, float(m) * phi);
             iridescence += cm * sm;
            }
        return iridescence = max(iridescence, vec3(0.0)); 
    }
#endif

// GGX Distribution, Schlick Fresnel, GGX-Smith Visibility
vec3 BRDF_Specular_GGX(vec3 incidentDirection, Geometry geometry, Material material, vec3 normal, vec3 specularColor, float roughness ) {

	float alpha = pow2( roughness ); // UE4's roughness

	vec3 halfDir = normalize( incidentDirection + geometry.viewDir );

	float dotNL = saturate( dot( normal, incidentDirection ) );
	float dotNV = saturate( dot( normal, geometry.viewDir ) );
	float dotNH = saturate( dot( normal, halfDir ) );
	float dotLH = saturate( dot( incidentDirection, halfDir ) );

    vec3 F = F_Schlick( specularColor, material.specularF90, dotLH );
    #ifdef MATERIAL_ENABLE_IRIDESCENCE
        F = mix(F, material.iridescenceSpecularColor, material.iridescenceFactor);
    #endif

    #ifdef MATERIAL_ENABLE_ANISOTROPY
        float GD = DG_GGX_anisotropic(halfDir, incidentDirection, geometry, alpha, dotNV, dotNL, dotNH);
    #else
        float GD = DG_GGX(alpha, dotNV, dotNL, dotNH);
    #endif

    return F * GD;
}

vec3 BRDF_Diffuse_Lambert(vec3 diffuseColor ) {
	return RECIPROCAL_PI * diffuseColor;
}
`;
var direct_irradiance_frag_define = "#include <ShadowFragmentDeclaration>\n\nvoid sheenLobe(Geometry geometry, Material material, vec3 incidentDirection, vec3 attenuationIrradiance, inout vec3 diffuseColor, inout vec3 specularColor){\n    #ifdef MATERIAL_ENABLE_SHEEN\n        diffuseColor *= material.sheenScaling;\n        specularColor *= material.sheenScaling;\n\n        specularColor += attenuationIrradiance * sheenBRDF(incidentDirection, geometry, material.sheenColor, material.sheenRoughness);\n    #endif\n}\n\nvoid addDirectRadiance(vec3 incidentDirection, vec3 color, Geometry geometry, Material material, inout ReflectedLight reflectedLight) {\n    float attenuation = 1.0;\n\n    #ifdef MATERIAL_ENABLE_CLEAR_COAT\n        float clearCoatDotNL = saturate( dot( geometry.clearCoatNormal, incidentDirection ) );\n        vec3 clearCoatIrradiance = clearCoatDotNL * color;\n\n        reflectedLight.directSpecular += material.clearCoat * clearCoatIrradiance * BRDF_Specular_GGX( incidentDirection, geometry, material, geometry.clearCoatNormal, vec3( 0.04 ), material.clearCoatRoughness );\n        attenuation -= material.clearCoat * F_Schlick(0.04, 1.0, geometry.clearCoatDotNV);\n    #endif\n\n    float dotNL = saturate( dot( geometry.normal, incidentDirection ) );\n    vec3 irradiance = dotNL * color * PI;\n\n    reflectedLight.directSpecular += attenuation * irradiance * BRDF_Specular_GGX( incidentDirection, geometry, material, geometry.normal, material.specularF0, material.roughness);\n    reflectedLight.directDiffuse += attenuation * irradiance * BRDF_Diffuse_Lambert( material.diffuseColor );\n\n    // Sheen Lobe\n    sheenLobe(geometry, material, incidentDirection, attenuation * irradiance, reflectedLight.directDiffuse, reflectedLight.directSpecular);\n\n}\n\n#ifdef SCENE_DIRECT_LIGHT_COUNT\n\n    void addDirectionalDirectLightRadiance(DirectLight directionalLight, Geometry geometry, Material material, inout ReflectedLight reflectedLight) {\n        vec3 color = directionalLight.color;\n        vec3 direction = -directionalLight.direction;\n\n		addDirectRadiance( direction, color, geometry, material, reflectedLight );\n\n    }\n\n#endif\n\n#ifdef SCENE_POINT_LIGHT_COUNT\n\n	void addPointDirectLightRadiance(PointLight pointLight, Geometry geometry, Material material, inout ReflectedLight reflectedLight) {\n\n		vec3 lVector = pointLight.position - geometry.position;\n		vec3 direction = normalize( lVector );\n\n		float lightDistance = length( lVector );\n\n		vec3 color = pointLight.color;\n		color *= clamp(1.0 - pow(lightDistance/pointLight.distance, 4.0), 0.0, 1.0);\n\n		addDirectRadiance( direction, color, geometry, material, reflectedLight );\n\n	}\n\n#endif\n\n#ifdef SCENE_SPOT_LIGHT_COUNT\n\n	void addSpotDirectLightRadiance(SpotLight spotLight, Geometry geometry, Material material, inout ReflectedLight reflectedLight) {\n\n		vec3 lVector = spotLight.position - geometry.position;\n		vec3 direction = normalize( lVector );\n\n		float lightDistance = length( lVector );\n		float angleCos = dot( direction, -spotLight.direction );\n\n		float spotEffect = smoothstep( spotLight.penumbraCos, spotLight.angleCos, angleCos );\n		float decayEffect = clamp(1.0 - pow(lightDistance/spotLight.distance, 4.0), 0.0, 1.0);\n\n		vec3 color = spotLight.color;\n		color *= spotEffect * decayEffect;\n\n		addDirectRadiance( direction, color, geometry, material, reflectedLight );\n\n	}\n\n\n#endif\n\nvoid addTotalDirectRadiance(Geometry geometry, Material material, inout ReflectedLight reflectedLight){\n    float shadowAttenuation = 1.0;\n\n    #ifdef SCENE_DIRECT_LIGHT_COUNT\n        shadowAttenuation = 1.0;\n        #ifdef SCENE_IS_CALCULATE_SHADOWS\n            shadowAttenuation *= sampleShadowMap();\n        #endif\n\n        DirectLight directionalLight;\n        for ( int i = 0; i < SCENE_DIRECT_LIGHT_COUNT; i ++ ) {\n            // warning: use `continue` syntax may trigger flickering bug in safri 16.1.\n            if(!isRendererCulledByLight(renderer_Layer.xy, scene_DirectLightCullingMask[i])){\n                directionalLight.color = scene_DirectLightColor[i];\n                #ifdef SCENE_IS_CALCULATE_SHADOWS\n                    if (i == 0) { // Sun light index is always 0\n                        directionalLight.color *= shadowAttenuation;\n                    }\n                #endif\n                directionalLight.direction = scene_DirectLightDirection[i];\n                addDirectionalDirectLightRadiance( directionalLight, geometry, material, reflectedLight );\n            }\n        }\n\n    #endif\n\n    #ifdef SCENE_POINT_LIGHT_COUNT\n\n        PointLight pointLight;\n\n        for ( int i = 0; i < SCENE_POINT_LIGHT_COUNT; i ++ ) {\n            if(!isRendererCulledByLight(renderer_Layer.xy, scene_PointLightCullingMask[i])){\n                pointLight.color = scene_PointLightColor[i];\n                pointLight.position = scene_PointLightPosition[i];\n                pointLight.distance = scene_PointLightDistance[i];\n\n                addPointDirectLightRadiance( pointLight, geometry, material, reflectedLight );\n            } \n        }\n\n    #endif\n\n    #ifdef SCENE_SPOT_LIGHT_COUNT\n\n        SpotLight spotLight;\n\n        for ( int i = 0; i < SCENE_SPOT_LIGHT_COUNT; i ++ ) {\n            if(!isRendererCulledByLight(renderer_Layer.xy, scene_SpotLightCullingMask[i])){\n                spotLight.color = scene_SpotLightColor[i];\n                spotLight.position = scene_SpotLightPosition[i];\n                spotLight.direction = scene_SpotLightDirection[i];\n                spotLight.distance = scene_SpotLightDistance[i];\n                spotLight.angleCos = scene_SpotLightAngleCos[i];\n                spotLight.penumbraCos = scene_SpotLightPenumbraCos[i];\n\n                addSpotDirectLightRadiance( spotLight, geometry, material, reflectedLight );\n            } \n        }\n\n    #endif\n}";
var ibl_frag_define = "// ------------------------Diffuse------------------------\n\n// sh need be pre-scaled in CPU.\nvec3 getLightProbeIrradiance(vec3 sh[9], vec3 normal){\n      normal.x = -normal.x;\n      vec3 result = sh[0] +\n\n            sh[1] * (normal.y) +\n            sh[2] * (normal.z) +\n            sh[3] * (normal.x) +\n\n            sh[4] * (normal.y * normal.x) +\n            sh[5] * (normal.y * normal.z) +\n            sh[6] * (3.0 * normal.z * normal.z - 1.0) +\n            sh[7] * (normal.z * normal.x) +\n            sh[8] * (normal.x * normal.x - normal.y * normal.y);\n    \n    return max(result, vec3(0.0));\n\n}\n\n// ------------------------Specular------------------------\n\n// ref: https://www.unrealengine.com/blog/physically-based-shading-on-mobile - environmentBRDF for GGX on mobile\nvec3 envBRDFApprox(vec3 f0, float f90, float roughness, float dotNV ) {\n\n    const vec4 c0 = vec4( - 1, - 0.0275, - 0.572, 0.022 );\n\n    const vec4 c1 = vec4( 1, 0.0425, 1.04, - 0.04 );\n\n    vec4 r = roughness * c0 + c1;\n\n    float a004 = min( r.x * r.x, exp2( - 9.28 * dotNV ) ) * r.x + r.y;\n\n    vec2 AB = vec2( -1.04, 1.04 ) * a004 + r.zw;\n\n    return f0 * AB.x + f90 * AB.y;\n}\n\n\nfloat getSpecularMIPLevel(float roughness, int maxMIPLevel ) {\n    return roughness * float(maxMIPLevel);\n}\n\nvec3 getReflectedVector(Geometry geometry, vec3 n) {\n    #ifdef MATERIAL_ENABLE_ANISOTROPY\n        vec3 r = reflect(-geometry.viewDir, geometry.anisotropicN);\n    #else\n        vec3 r = reflect(-geometry.viewDir, n);\n    #endif\n\n    return r;\n}\n\nvec3 getLightProbeRadiance(Geometry geometry, vec3 normal, float roughness, int maxMIPLevel, float specularIntensity) {\n\n    #ifndef SCENE_USE_SPECULAR_ENV\n        return vec3(0);\n    #else\n        vec3 reflectVec = getReflectedVector(geometry, normal);\n        reflectVec.x = -reflectVec.x; // TextureCube is left-hand,so x need inverse\n        \n        float specularMIPLevel = getSpecularMIPLevel(roughness, maxMIPLevel );\n\n        #ifdef HAS_TEX_LOD\n            vec4 envMapColor = textureCubeLodEXT( scene_EnvSpecularSampler, reflectVec, specularMIPLevel );\n        #else\n            vec4 envMapColor = textureCube( scene_EnvSpecularSampler, reflectVec, specularMIPLevel );\n        #endif\n\n        #ifdef SCENE_IS_DECODE_ENV_RGBM\n            envMapColor.rgb = RGBMToLinear(envMapColor, 5.0).rgb;\n        #elif defined(ENGINE_NO_SRGB)\n            envMapColor = sRGBToLinear(envMapColor);\n        #endif\n        \n        return envMapColor.rgb * specularIntensity;\n\n    #endif\n\n}\n\n\nvoid evaluateSheenIBL(Geometry geometry, Material material, float radianceAttenuation, inout vec3 diffuseColor, inout vec3 specularColor){\n    #ifdef MATERIAL_ENABLE_SHEEN\n        diffuseColor *= material.sheenScaling;\n        specularColor *= material.sheenScaling;\n\n        vec3 reflectance = material.specularAO * radianceAttenuation * material.approxIBLSheenDG * material.sheenColor;\n        specularColor += reflectance;\n    #endif\n}";
var pbr_frag = "Geometry geometry;\nMaterial material;\nReflectedLight reflectedLight = ReflectedLight( vec3( 0.0 ), vec3( 0.0 ), vec3( 0.0 ), vec3( 0.0 ) );\n\ninitGeometry(geometry, gl_FrontFacing);\ninitMaterial(material, geometry);\n\n// Direct Light\naddTotalDirectRadiance(geometry, material, reflectedLight);\n\n// IBL diffuse\n#ifdef SCENE_USE_SH\n    vec3 irradiance = getLightProbeIrradiance(scene_EnvSH, geometry.normal);\n    irradiance *= scene_EnvMapLight.diffuseIntensity;\n#else\n   vec3 irradiance = scene_EnvMapLight.diffuse * scene_EnvMapLight.diffuseIntensity;\n   irradiance *= PI;\n#endif\n\nreflectedLight.indirectDiffuse += material.diffuseAO * irradiance * BRDF_Diffuse_Lambert( material.diffuseColor );\n\n// IBL specular\nvec3 radiance = getLightProbeRadiance(geometry, geometry.normal, material.roughness, int(scene_EnvMapLight.mipMapLevel), scene_EnvMapLight.specularIntensity);\nfloat radianceAttenuation = 1.0;\n\n// IBL Clear Coat\n#ifdef MATERIAL_ENABLE_CLEAR_COAT\n    vec3 clearCoatRadiance = getLightProbeRadiance( geometry, geometry.clearCoatNormal, material.clearCoatRoughness, int(scene_EnvMapLight.mipMapLevel), scene_EnvMapLight.specularIntensity );\n\n    reflectedLight.indirectSpecular += material.specularAO * clearCoatRadiance * material.clearCoat * envBRDFApprox(vec3( 0.04 ), 1.0, material.clearCoatRoughness, geometry.clearCoatDotNV);\n    radianceAttenuation -= material.clearCoat * F_Schlick(0.04, 1.0, geometry.clearCoatDotNV);\n#endif\n\n#ifdef MATERIAL_ENABLE_IRIDESCENCE\n    vec3 speculaColor = mix(material.specularF0, material.iridescenceSpecularColor, material.iridescenceFactor);\n#else\n    vec3 speculaColor = material.specularF0;\n#endif\n\nreflectedLight.indirectSpecular += material.specularAO * radianceAttenuation * radiance * envBRDFApprox(speculaColor, material.specularF90, material.roughness, geometry.dotNV);\n\n\n// IBL Sheen\nevaluateSheenIBL(geometry, material, radianceAttenuation, reflectedLight.indirectDiffuse, reflectedLight.indirectSpecular);\n\n\n// Final color\nvec3 totalDiffuseColor = reflectedLight.directDiffuse + reflectedLight.indirectDiffuse;\nvec3 totalSpecularColor = reflectedLight.directSpecular + reflectedLight.indirectSpecular;\n\n#ifdef MATERIAL_ENABLE_TRANSMISSION \n    vec3 refractionTransmitted = evaluateTransmission(geometry, material);\n    totalDiffuseColor = mix(totalDiffuseColor, refractionTransmitted, material.transmission);\n#endif\n\nvec4 finalColor = vec4(totalDiffuseColor + totalSpecularColor, material.opacity);\n\n\n// Emissive\nvec3 emissiveRadiance = material_EmissiveColor;\n#ifdef MATERIAL_HAS_EMISSIVETEXTURE\n    emissiveRadiance *= texture2DSRGB(material_EmissiveTexture, v_uv).rgb;\n#endif\n\nfinalColor.rgb += emissiveRadiance;\n\n\ngl_FragColor = finalColor;\n";
var btdf = "#include <refraction>\n\n#ifdef MATERIAL_ENABLE_TRANSMISSION \n    uniform sampler2D camera_OpaqueTexture;\n    vec3 evaluateTransmission(Geometry geometry, Material material) {\n        RefractionModelResult ray;\n        #if REFRACTION_MODE == 0  \n            // RefractionMode.Sphere\n            refractionModelSphere(-geometry.viewDir, geometry.position, geometry.normal, material.IOR, material.thickness, ray);\n        #elif REFRACTION_MODE == 1\n            // RefractionMode.Planar\n            refractionModelPlanar(-geometry.viewDir, geometry.position, geometry.normal, material.IOR, material.thickness, ray);\n        #endif\n\n        vec3 refractedRayExit = ray.positionExit;\n\n        // We calculate the screen space position of the refracted point\n        vec4 samplingPositionNDC = camera_ProjMat * camera_ViewMat * vec4( refractedRayExit, 1.0 );\n        vec2 refractionCoords = (samplingPositionNDC.xy / samplingPositionNDC.w) * 0.5 + 0.5;\n\n        // Sample the opaque texture to get the transmitted light\n        vec3 refractionTransmitted = texture2DSRGB(camera_OpaqueTexture, refractionCoords).rgb;\n        refractionTransmitted *= material.diffuseColor;\n         \n        // Use specularFGD as an approximation of the fresnel effect\n        // https://blog.selfshadow.com/publications/s2017-shading-course/imageworks/s2017_pbs_imageworks_slides_v2.pdf\n        refractionTransmitted *= (1.0 - material.envSpecularDFG);\n\n       #ifdef MATERIAL_HAS_THICKNESS\n            // Absorption coefficient from Disney: http://blog.selfshadow.com/publications/s2015-shading-course/burley/s2015_pbs_disney_bsdf_notes.pdf\n            vec3 transmittance = min(vec3(1.0), exp(-material.absorptionCoefficient * ray.transmissionLength));\n            refractionTransmitted *= transmittance;\n       #endif\n        \n    return refractionTransmitted;\n    }\n#endif";
var refraction = "#ifdef MATERIAL_ENABLE_TRANSMISSION \n	struct RefractionModelResult {\n	    float transmissionLength;         // length of the transmission during refraction through the shape\n	    vec3 positionExit;      // out ray position\n	    // vec3 directionExit;     // out ray direction\n	};\n\n	//https://docs.unity3d.com/Packages/com.unity.render-pipelines.high-definition@15.0/manual/refraction-models.html\n	 void refractionModelSphere(vec3 V, vec3 positionWS, vec3 normalWS, float ior, float thickness, out RefractionModelResult ray) {\n	    // Refracted ray\n	    vec3 R1 = refract(V, normalWS, 1.0 / ior);\n	    // Center of the tangent sphere\n	    // vec3 C = positionWS - normalWS * thickness * 0.5;\n\n	    // Second refraction (tangent sphere out)\n	    float dist = dot(-normalWS, R1) * thickness;\n	    // Out hit point in the tangent sphere\n	    vec3 P1 = positionWS + R1 * dist;\n	    // Out normal\n	    // vec3 N1 = safeNormalize(C - P1);\n	    // Out refracted ray\n	    // vec3 R2 = refract(R1, N1, ior);\n\n	    ray.transmissionLength = dist;\n	    ray.positionExit = P1;\n	    // ray.directionExit = R2; \n	}\n\n	void refractionModelPlanar(vec3 V, vec3 positionWS, vec3 normalWS, float ior, float thickness, out RefractionModelResult ray) {\n	    // Refracted ray\n	    vec3 R = refract(V, normalWS, 1.0 / ior);\n	    // Optical depth within the thin plane\n	    float dist = thickness / max(dot(-normalWS, R), 1e-5f);\n\n	    ray.transmissionLength = dist;\n	    ray.positionExit = vec3(positionWS + R * dist);\n	    // ray.directionExit = V;\n	}\n\n#endif";
